// ─── Category color themes (subtle accents only) ───
type CategoryTheme = {
  text: string;
  textStrong: string;
  bg: string;
  bgSoft: string;
  border: string;
  borderSoft: string;
  dot: string;
};

const categoryThemes: Record<string, CategoryTheme> = {
  // 数据研究 — 深蓝绿色
  '1037-research-douyin': {
    text: 'text-teal-600 dark:text-teal-400',
    textStrong: 'text-teal-700 dark:text-teal-300',
    bg: 'bg-teal-50/70 dark:bg-teal-900/20',
    bgSoft: 'bg-teal-50/40 dark:bg-teal-900/10',
    border: 'border-teal-200/70 dark:border-teal-800/50',
    borderSoft: 'border-teal-100/60 dark:border-teal-900/30',
    dot: 'bg-teal-500',
  },
  // 产品研究 — 柔和蓝色
  'immersing-ai-vocal': {
    text: 'text-sky-600 dark:text-sky-400',
    textStrong: 'text-sky-700 dark:text-sky-300',
    bg: 'bg-sky-50/70 dark:bg-sky-900/20',
    bgSoft: 'bg-sky-50/40 dark:bg-sky-900/10',
    border: 'border-sky-200/70 dark:border-sky-800/50',
    borderSoft: 'border-sky-100/60 dark:border-sky-900/30',
    dot: 'bg-sky-500',
  },
  // 整合传播 — 暖绿色
  'cultural-festival-publicity': {
    text: 'text-emerald-600 dark:text-emerald-400',
    textStrong: 'text-emerald-700 dark:text-emerald-300',
    bg: 'bg-emerald-50/70 dark:bg-emerald-900/20',
    bgSoft: 'bg-emerald-50/40 dark:bg-emerald-900/10',
    border: 'border-emerald-200/70 dark:border-emerald-800/50',
    borderSoft: 'border-emerald-100/60 dark:border-emerald-900/30',
    dot: 'bg-emerald-500',
  },
  // 公益教育 — 浅棕绿色
  'summer-teaching': {
    text: 'text-lime-700 dark:text-lime-400',
    textStrong: 'text-lime-800 dark:text-lime-300',
    bg: 'bg-lime-50/70 dark:bg-lime-900/20',
    bgSoft: 'bg-lime-50/40 dark:bg-lime-900/10',
    border: 'border-lime-200/70 dark:border-lime-800/50',
    borderSoft: 'border-lime-100/60 dark:border-lime-900/30',
    dot: 'bg-lime-600',
  },
};

const defaultTheme: CategoryTheme = categoryThemes['1037-research-douyin'];

function getTheme(id: string): CategoryTheme {
  return categoryThemes[id] || defaultTheme;
}

// ─── Featured Project Card (P.01 — full-width, left/right split) ───
