import { useState } from 'react';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { Award, Eye } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { Visualization } from '@/data/visualizations';

interface VisualizationPreviewProps {
  visualization: Visualization;
  onViewDetails: () => void;
}

export default function VisualizationPreview({ visualization, onViewDetails }: VisualizationPreviewProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';
  const [isHovered, setIsHovered] = useState(false);

  const keywords = isZh ? visualization.keywordsZh : visualization.keywordsEn;
  const awards = isZh ? visualization.awardsZh : visualization.awardsEn;

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 0.7 }}
      className="w-full"
    >
      <div className="flex flex-col lg:flex-row gap-10 lg:gap-14">
        {/* 左侧图片区 */}
        <div
          className="lg:w-[58%] relative cursor-pointer group"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          onClick={onViewDetails}
        >
          <div
            className={cn(
              'relative overflow-hidden rounded-2xl',
              'bg-ivory-100 dark:bg-ocean-800/50',
              'border border-forest-200/50 dark:border-ocean-700',
              'shadow-lg shadow-forest-900/5 dark:shadow-black/10',
              'p-5 md:p-6'
            )}
          >
            {/* 纸张纹理 */}
            <div
              className="absolute inset-0 pointer-events-none opacity-15"
              style={{
                backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`,
                backgroundSize: '150px 150px',
                mixBlendMode: 'overlay',
                borderRadius: 'inherit',
              }}
            />

            {/* Featured标签 */}
            <div className="absolute top-4 right-4 z-10">
              <span className="px-3 py-1.5 rounded-md bg-forest-500/85 backdrop-blur-sm text-xs font-medium text-white">
                {isZh ? '重点信息可视化作品' : 'Featured Visualization'}
              </span>
            </div>

            {/* 图片容器 */}
            <div className="relative aspect-[4/5] md:aspect-[3/4] lg:h-[640px] xl:h-[680px] overflow-hidden rounded-xl bg-ivory-50 dark:bg-ocean-900/50">
              <motion.img
                src={visualization.coverImage}
                alt={isZh ? visualization.titleZh : visualization.titleEn}
                className="w-full h-full object-contain"
                animate={{ scale: isHovered ? 1.02 : 1 }}
                transition={{ duration: 0.35 }}
              />

              {/* Hover蒙层 */}
              <motion.div
                className="absolute inset-0 bg-forest-900/35 flex flex-col items-center justify-center"
                initial={{ opacity: 0 }}
                animate={{ opacity: isHovered ? 1 : 0 }}
                transition={{ duration: 0.3 }}
              >
                <div className="w-14 h-14 rounded-full bg-ivory-100/90 backdrop-blur-sm flex items-center justify-center mb-3">
                  <Eye className="w-6 h-6 text-forest-700" />
                </div>
                <span className="text-white font-medium text-base tracking-wider">
                  {isZh ? '查看完整作品' : 'View Full Visualization'}
                </span>
              </motion.div>
            </div>
          </div>
        </div>

        {/* 右侧信息区 */}
        <div className="lg:w-[42%] flex flex-col justify-center">
          <div className="space-y-6">
            {/* 类型与年份 */}
            <div className="flex items-center gap-3">
              <span className="text-[13px] font-medium text-forest-500 tracking-wide uppercase">
                {isZh ? visualization.categoryZh : visualization.categoryEn}
              </span>
              <span className="w-1 h-1 rounded-full bg-ocean-300" />
              <span className="text-[13px] text-ocean-400">{visualization.year}</span>
            </div>

            {/* 中文标题 */}
            <h3 className="text-[28px] md:text-[34px] font-display font-semibold text-ocean-800 dark:text-ivory-50 leading-[1.35]">
              {isZh ? visualization.titleZh : visualization.titleEn}
            </h3>

            {/* 英文副标题 */}
            {visualization.titleEn && (
              <p className="text-[15px] md:text-[16px] text-ocean-500 dark:text-ivory-400 leading-relaxed">
                {isZh ? visualization.titleEn : visualization.titleZh}
              </p>
            )}

            {/* 简介 */}
            <p className="text-[15px] md:text-[16px] text-ocean-600 dark:text-ivory-300 leading-[1.8]">
              {isZh ? visualization.overviewShortZh : visualization.overviewShortEn}
            </p>

            {/* 职责 */}
            <div>
              <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider mb-2">
                {isZh ? '我的职责' : 'My Role'}
              </h4>
              <p className="text-[15px] text-ocean-600 dark:text-ivory-300 leading-[1.7]">
                {isZh ? visualization.roleIntroZh : visualization.roleIntroEn}
              </p>
            </div>

            {/* 关键词 */}
            <div>
              <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider mb-3">
                {isZh ? '关键词' : 'Keywords'}
              </h4>
              <div className="flex flex-wrap gap-2">
                {keywords.map((keyword, index) => (
                  <span
                    key={index}
                    className={cn(
                      'px-3 py-1.5 rounded-full text-[12px] font-medium',
                      'bg-forest-100/80 dark:bg-forest-900/40',
                      'text-forest-700 dark:text-forest-300',
                      'border border-forest-200/60 dark:border-forest-700/40'
                    )}
                  >
                    {keyword}
                  </span>
                ))}
              </div>
            </div>

            {/* 奖项 */}
            {awards.length > 0 && (
              <div className="p-4 rounded-xl bg-amber-50/60 dark:bg-amber-900/20 border-l-4 border-amber-400/70 dark:border-amber-500/50">
                <div className="flex items-start gap-3">
                  <Award className="w-4 h-4 text-amber-500 mt-0.5 flex-shrink-0" />
                  <div className="space-y-1">
                    {awards.map((award, index) => (
                      <p key={index} className="text-sm text-amber-700 dark:text-amber-300">
                        {award}
                      </p>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* 查看详情按钮 */}
            <button
              onClick={onViewDetails}
              className={cn(
                'inline-flex items-center gap-2 px-6 py-3 rounded-full',
                'bg-forest-600 dark:bg-forest-500',
                'text-white text-sm font-medium',
                'hover:bg-forest-700 dark:hover:bg-forest-600',
                'transition-colors duration-200'
              )}
            >
              <Eye className="w-4 h-4" />
              {isZh ? '查看详情' : 'View Details'}
            </button>
          </div>
        </div>
      </div>
    </motion.div>
  );
}
