import { useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { FileText, Award, Eye, ChevronRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { DeckWork } from '@/data/deckWorks';
import { usePdfRenderer } from '@/hooks/usePdfRenderer';

interface DeckCardProps {
  deck: DeckWork;
  index: number;
  onClick: () => void;
}

export default function DeckCard({ deck, index, onClick }: DeckCardProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const title = isZh ? deck.titleZh : deck.titleEn;
  const category = isZh ? deck.categoryZh : deck.categoryEn;
  const summary = isZh ? deck.summaryZh : deck.summaryEn;
  const role = isZh ? deck.roleZh : deck.roleEn;
  const keywords = isZh ? deck.keywordsZh : deck.keywordsEn;
  const award = isZh ? deck.awardZh : deck.awardEn;

  const { loading, error, numPages, renderPage } = usePdfRenderer(deck.pdfUrl);

  // Render first page as cover
  useEffect(() => {
    if (loading || error || !canvasRef.current || !containerRef.current) return;
    const width = containerRef.current.clientWidth;
    if (width > 0) {
      renderPage(1, canvasRef.current, width).catch((err) => {
        console.error(`[DeckCard] Failed to render cover: ${deck.pdfUrl}`, err);
      });
    }
  }, [loading, error, renderPage, deck.pdfUrl]);

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 0.6, delay: index * 0.1, ease: 'easeOut' }}
      className={cn(
        'flex flex-col h-full',
        'overflow-hidden',
        'bg-ivory-50 dark:bg-ocean-800',
        'border border-forest-200/60 dark:border-ocean-700',
        'rounded-[20px]',
        'shadow-lg shadow-forest-900/5 dark:shadow-black/10',
        'transition-all duration-300 ease-out',
        'hover:-translate-y-[3px]',
        'hover:border-forest-300 dark:hover:border-forest-600',
        'hover:shadow-xl hover:shadow-forest-900/10 dark:hover:shadow-black/20'
      )}
    >
      {/* 16:9 PDF cover preview */}
      <div
        ref={containerRef}
        className="relative w-full flex-shrink-0 overflow-hidden group"
        style={{ aspectRatio: '16 / 9', background: '#f4f1e8' }}
        onClick={onClick}
      >
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-ivory-100 to-ivory-200 dark:from-ocean-700/40 dark:to-ocean-800 animate-pulse">
            <FileText className="w-8 h-8 text-forest-300/60 dark:text-forest-700/40" />
          </div>
        )}

        {error ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-gradient-to-br from-ivory-50 to-ivory-200 dark:from-ocean-700/40 dark:to-ocean-900">
            <FileText className="w-8 h-8 text-forest-300/60 dark:text-forest-700/40 mb-2" />
            <p className="text-xs text-ocean-400 dark:text-ivory-500">
              {isZh ? '方案预览暂不可用' : 'Deck preview unavailable'}
            </p>
          </div>
        ) : (
          !loading && (
            <canvas
              ref={canvasRef}
              className="absolute inset-0 w-full h-full transition-transform duration-300 ease-out group-hover:scale-[1.015]"
              style={{ objectFit: 'cover', objectPosition: 'center' }}
            />
          )
        )}

        {/* Type label — top right */}
        {!error && (
          <div className="absolute top-3 right-3 z-10">
            <span className={cn(
              'px-2.5 py-1 rounded-md text-[10px] font-medium backdrop-blur-sm',
              'bg-forest-500/85 text-white'
            )}>
              {category}
            </span>
          </div>
        )}

        {/* Page count — bottom left */}
        {!error && (
          <div className="absolute bottom-3 left-3 z-10">
            <span className="px-2 py-0.5 rounded-md text-[10px] font-medium bg-white/80 backdrop-blur-sm text-ocean-600">
              {deck.pageCount} {isZh ? '页' : 'Pages'}
            </span>
          </div>
        )}

        {/* Hover overlay */}
        {!error && !loading && (
          <div className="absolute inset-0 bg-forest-900/0 hover:bg-forest-900/20 flex items-center justify-center pointer-events-none transition-colors duration-300">
            <div className="opacity-0 hover:opacity-100 flex items-center gap-1.5 text-white text-sm font-medium transition-opacity duration-300">
              <Eye className="w-4 h-4" />
              {isZh ? '查看完整方案' : 'View Deck'}
            </div>
          </div>
        )}
      </div>

      {/* Info area */}
      <div className="flex flex-col flex-1 p-5 space-y-3">
        {/* Category + year */}
        <div className="flex items-center gap-2 text-xs font-medium tracking-wide">
          <span className="uppercase text-forest-600 dark:text-forest-400">{category}</span>
          <span className="w-1 h-1 rounded-full bg-forest-300 dark:bg-forest-600" />
          <span className="text-ocean-400 dark:text-ivory-500">{deck.year}</span>
        </div>

        {/* Title */}
        <div>
          <h3 className="text-lg font-display font-semibold leading-snug text-ocean-800 dark:text-ivory-50">
            {title}
          </h3>
          <p className="text-xs text-ocean-400 dark:text-ivory-500 mt-1">
            {isZh ? deck.titleEn : deck.titleZh}
          </p>
        </div>

        {/* Summary */}
        <p className="text-sm leading-relaxed text-ocean-500 dark:text-ivory-400 line-clamp-3">
          {summary}
        </p>

        {/* Role */}
        <p className="text-[12px] font-medium text-ocean-600 dark:text-ivory-300 line-clamp-2">
          {role}
        </p>

        {/* Keywords */}
        <div className="flex flex-wrap gap-1.5">
          {keywords.slice(0, 4).map((kw, i) => (
            <span
              key={i}
              className="inline-flex items-center rounded-full px-2.5 py-0.5 text-[11px] font-medium bg-forest-50 text-forest-700 border border-forest-200/80 dark:bg-forest-900/30 dark:text-forest-300 dark:border-forest-700/60"
            >
              {kw}
            </span>
          ))}
        </div>

        {/* Award */}
        {award && (
          <div className="flex items-center gap-2 px-3 py-2 rounded-lg bg-sunlight-50/80 dark:bg-sunlight-900/20 border border-sunlight-200/60 dark:border-sunlight-700/30">
            <Award className="w-3.5 h-3.5 text-sunlight-600 dark:text-sunlight-400 flex-shrink-0" />
            <span className="text-[11px] font-medium text-sunlight-700 dark:text-sunlight-400">
              {award}
            </span>
          </div>
        )}

        {/* Button */}
        <div className="mt-auto pt-2">
          <button
            onClick={onClick}
            disabled={error}
            className={cn(
              'inline-flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium',
              'bg-forest-600 text-white',
              'hover:bg-forest-700',
              'transition-colors duration-200',
              error && 'opacity-40 cursor-not-allowed'
            )}
          >
            <Eye className="w-3.5 h-3.5" />
            {isZh ? '查看完整方案' : 'View Deck'}
            <ChevronRight className="w-3.5 h-3.5 transition-transform group-hover:translate-x-[3px]" />
          </button>
        </div>
      </div>
    </motion.div>
  );
}
