import { useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { ExternalLink, Eye, ChevronDown } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { AgentPlatform } from '@/data/agentPlatforms';

interface AgentPlatformPreviewProps {
  agent: AgentPlatform;
  onViewDetails: () => void;
}

export default function AgentPlatformPreview({ agent, onViewDetails }: AgentPlatformPreviewProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageRatio, setImageRatio] = useState<number | null>(null);
  const [showScrollHint, setShowScrollHint] = useState(true);
  const keywords = isZh ? agent.keywordsZh : agent.keywordsEn;

  const handleImageLoad = useCallback((e: React.SyntheticEvent<HTMLImageElement>) => {
    const img = e.currentTarget;
    if (img.naturalWidth > 0 && img.naturalHeight > 0) {
      setImageRatio(img.naturalWidth / img.naturalHeight);
    }
    setImageLoaded(true);
  }, []);

  // Determine display mode based on image ratio
  const isLandscape = imageRatio !== null && imageRatio >= 1.2;
  const isScrollable = !isLandscape;

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 0.7 }}
      className="w-full"
    >
      {/* Fixed-height card container */}
      <div
        className={cn(
          'flex flex-col lg:flex-row h-[520px]',
          'overflow-hidden',
          'bg-ivory-50 dark:bg-ocean-800',
          'border border-forest-200/60 dark:border-ocean-700',
          'rounded-[20px]',
          'shadow-lg shadow-forest-900/5 dark:shadow-black/10'
        )}
      >
        {/* Left: Product screenshot area - 58% width */}
        <div className="relative w-full lg:w-[58%] h-[280px] lg:h-full flex-shrink-0 cursor-pointer group">
          {/* Browser window mockup */}
          <div
            className={cn(
              'relative w-full h-full flex flex-col',
              'overflow-hidden'
            )}
          >
            {/* Browser top bar - fixed height */}
            <div className="flex-shrink-0 flex items-center gap-2 px-3 py-2.5 bg-ocean-800 dark:bg-ocean-900">
              <div className="flex gap-1.5">
                <span className="w-3 h-3 rounded-full bg-red-500/80" />
                <span className="w-3 h-3 rounded-full bg-amber-500/80" />
                <span className="w-3 h-3 rounded-full bg-green-500/80" />
              </div>
              <span className="text-xs text-ocean-400 dark:text-ocean-500 truncate flex-1 text-center">
                {agent.platform} - {isZh ? agent.titleZh : agent.titleEn}
              </span>
            </div>

            {/* Content area - fills remaining space */}
            <div className="flex-1 relative bg-ivory-50 dark:bg-ocean-900/80 min-h-0 overflow-hidden">
              {/* Live badge */}
              <div className="absolute top-3 right-3 z-10">
                <span className="px-3 py-1.5 rounded-md bg-forest-500/85 backdrop-blur-sm text-xs font-medium text-white">
                  {isZh ? '可在线体验' : 'Live AI Product'}
                </span>
              </div>

              {/* Scrollable preview for non-landscape images */}
              {isScrollable ? (
                <div
                  className="relative w-full h-full overflow-y-auto overflow-x-hidden"
                  onScroll={(e) => {
                    setShowScrollHint((e.currentTarget as HTMLDivElement).scrollTop < 20);
                  }}
                  style={{ scrollbarWidth: 'thin' }}
                >
                  {!imageLoaded && (
                    <div className="w-full h-full animate-pulse bg-gradient-to-b from-ivory-100 via-ivory-200 to-ivory-100 dark:from-ocean-700/40 dark:via-ocean-700/60 dark:to-ocean-700/40" />
                  )}
                  <img
                    src={agent.coverImage}
                    alt={isZh ? agent.titleZh : agent.titleEn}
                    loading="lazy"
                    decoding="async"
                    onLoad={handleImageLoad}
                    className="block w-full h-auto transition-opacity duration-500"
                    style={{
                      maxWidth: 'none',
                      objectFit: 'unset',
                      opacity: imageLoaded ? 1 : 0
                    }}
                  />

                  {/* Scroll hint */}
                  {showScrollHint && imageLoaded && (
                    <motion.div
                      initial={{ opacity: 1 }}
                      animate={{ opacity: showScrollHint ? 1 : 0 }}
                      transition={{ duration: 0.3 }}
                      className="absolute bottom-0 left-0 right-0 flex flex-col items-center gap-1 py-3 pointer-events-none"
                      style={{ background: 'linear-gradient(to top, rgba(247,244,236,0.92) 40%, transparent 100%)' }}
                    >
                      <span className="text-[11px] text-ocean-400 font-medium">
                        {isZh ? '滑动查看平台' : 'Scroll to explore'}
                      </span>
                      <motion.div animate={{ y: [0, 5, 0] }} transition={{ duration: 1.5, repeat: Infinity, ease: 'easeInOut' }}>
                        <ChevronDown className="w-4 h-4 text-forest-400" />
                      </motion.div>
                    </motion.div>
                  )}
                </div>
              ) : (
                /* Cover mode for landscape images */
                <div className="relative w-full h-full overflow-hidden">
                  {!imageLoaded && (
                    <div className="absolute inset-0 w-full h-full animate-pulse bg-gradient-to-b from-ivory-100 via-ivory-200 to-ivory-100 dark:from-ocean-700/40 dark:via-ocean-700/60 dark:to-ocean-700/40" />
                  )}
                  <img
                    src={agent.coverImage}
                    alt={isZh ? agent.titleZh : agent.titleEn}
                    loading="lazy"
                    decoding="async"
                    onLoad={handleImageLoad}
                    className="absolute inset-0 w-full h-full transition-opacity duration-500"
                    style={{
                      objectFit: 'cover',
                      objectPosition: 'top center',
                      opacity: imageLoaded ? 1 : 0
                    }}
                  />
                </div>
              )}

              {/* Hover overlay */}
              {imageLoaded && (
                <div className="absolute inset-0 bg-forest-900/0 group-hover:bg-forest-900/20 flex items-center justify-center pointer-events-none transition-colors duration-300">
                  <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col items-center">
                    <div className="w-14 h-14 rounded-full bg-ivory-100/90 backdrop-blur-sm flex items-center justify-center mb-3">
                      <Eye className="w-6 h-6 text-forest-700" />
                    </div>
                    <span className="text-white font-medium text-base tracking-wider">
                      {isZh ? '探索智能体平台' : 'Explore the Platform'}
                    </span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right: Info area - 42% width */}
        <div className="flex flex-col w-full lg:w-[42%] p-6 lg:p-8">
          {/* Type & status */}
          <div className="flex flex-wrap items-center gap-3 mb-4">
            <span className="text-[13px] font-medium text-forest-500 tracking-wide uppercase">
              {isZh ? agent.categoryZh : agent.categoryEn}
            </span>
            <span className="w-1 h-1 rounded-full bg-ocean-300" />
            <span className="text-[13px] text-ocean-400">{agent.year}</span>
            <span className="w-1 h-1 rounded-full bg-ocean-300" />
            <span className="px-2.5 py-1 rounded-md bg-green-100/80 dark:bg-green-900/40 text-[12px] font-medium text-green-700 dark:text-green-400">
              {isZh ? agent.statusZh : agent.statusEn}
            </span>
          </div>

          {/* Title */}
          <h3 className="text-xl lg:text-2xl font-display font-semibold text-ocean-800 dark:text-ivory-50 leading-[1.35] mb-2">
            {isZh ? agent.titleZh : agent.titleEn}
          </h3>
          <p className="text-[14px] text-ocean-500 dark:text-ivory-400 mb-4">
            {isZh ? agent.titleEn : agent.titleZh}
          </p>

          {/* Overview - max 4 lines */}
          <p className="text-sm text-ocean-600 dark:text-ivory-300 leading-[1.7] line-clamp-4 mb-5">
            {isZh ? agent.overviewZh : agent.overviewEn}
          </p>

          {/* Core features - only names */}
          <div className="mb-5">
            <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider mb-3">
              {isZh ? '核心功能' : 'Core Features'}
            </h4>
            <div className="grid grid-cols-2 gap-2">
              {agent.features.map((feature, index) => (
                <span
                  key={index}
                  className={cn(
                    'inline-flex items-center gap-2 px-3 py-1.5 rounded-lg',
                    'bg-forest-50/80 dark:bg-forest-900/20',
                    'border border-forest-200/40 dark:border-forest-700/30',
                    'text-xs font-medium text-ocean-700 dark:text-ivory-300'
                  )}
                >
                  <span className="w-1.5 h-1.5 rounded-full bg-forest-500" />
                  {isZh ? feature.nameZh : feature.nameEn}
                </span>
              ))}
            </div>
          </div>

          {/* Keywords */}
          <div className="mb-4">
            <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider mb-2">
              {isZh ? '关键词' : 'Keywords'}
            </h4>
            <div className="flex flex-wrap gap-1.5">
              {keywords.slice(0, 4).map((keyword, index) => (
                <span
                  key={index}
                  className={cn(
                    'px-2.5 py-1 rounded-full text-[11px] font-medium',
                    'bg-forest-100/80 dark:bg-forest-900/40',
                    'text-forest-700 dark:text-forest-300',
                    'border border-forest-200/60 dark:border-forest-700/40'
                  )}
                >
                  {keyword}
                </span>
              ))}
            </div>
          </div>

          {/* Action buttons - fixed at bottom */}
          <div className="mt-auto flex flex-wrap gap-3">
            <a
              href={agent.liveUrl}
              target="_blank"
              rel="noopener noreferrer"
              className={cn(
                'inline-flex items-center gap-2 px-5 py-2.5 rounded-full',
                'bg-forest-600 dark:bg-forest-500',
                'text-white text-xs font-medium',
                'hover:bg-forest-700 dark:hover:bg-forest-600',
                'transition-colors duration-200'
              )}
            >
              {isZh ? '立即体验' : 'Launch Platform'}
              <ExternalLink className="w-3.5 h-3.5" />
            </a>
            <button
              onClick={onViewDetails}
              className={cn(
                'inline-flex items-center gap-2 px-5 py-2.5 rounded-full',
                'border-2 border-forest-400 dark:border-forest-500',
                'text-forest-600 dark:text-forest-400 text-xs font-medium',
                'hover:bg-forest-50 dark:hover:bg-forest-900/20',
                'transition-colors duration-200'
              )}
            >
              <Eye className="w-3.5 h-3.5" />
              {isZh ? '查看详情' : 'View Details'}
            </button>
          </div>

          <p className="text-[10px] text-ocean-400 dark:text-ivory-500 mt-3">
            {isZh ? '外部平台可能需要登录扣子账号。' : 'External platform may require login.'}
          </p>
        </div>
      </div>
    </motion.div>
  );
}
