import { useState, useEffect, useRef } from 'react';

interface MousePosition {
  x: number;
  y: number;
}

interface UseMousePositionOptions {
  lerpFactor?: number;
  initialPosition?: MousePosition;
  enabled?: boolean;
}

export function useMousePosition({
  lerpFactor = 0.1,
  initialPosition = { x: 0, y: 0 },
  enabled = true,
}: UseMousePositionOptions = {}): MousePosition {
  const [position, setPosition] = useState<MousePosition>(initialPosition);
  const targetRef = useRef<MousePosition>(initialPosition);
  const currentRef = useRef<MousePosition>(initialPosition);
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    if (!enabled) return;

    const handleMouseMove = (event: MouseEvent) => {
      targetRef.current = {
        x: event.clientX,
        y: event.clientY,
      };
    };

    const animate = () => {
      const target = targetRef.current;
      const current = currentRef.current;

      const nextX = current.x + (target.x - current.x) * lerpFactor;
      const nextY = current.y + (target.y - current.y) * lerpFactor;

      currentRef.current = { x: nextX, y: nextY };
      setPosition({ x: nextX, y: nextY });

      rafRef.current = requestAnimationFrame(animate);
    };

    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    rafRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
    };
  }, [lerpFactor, enabled]);

  return position;
}
