import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { Play } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { Video } from '@/data/videos';

interface VideoCardProps {
  video: Video;
  index: number;
  onClick: () => void;
}

export default function VideoCard({ video, index, onClick }: VideoCardProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 0.6, delay: index * 0.1 }}
      className="group cursor-pointer"
      onClick={onClick}
    >
      <div
        className={cn(
          'relative overflow-hidden rounded-2xl',
          'bg-ivory-50 dark:bg-ocean-800',
          'border border-forest-200/60 dark:border-ocean-700',
          'shadow-lg shadow-forest-900/5 dark:shadow-black/10',
          'transition-all duration-300',
          'hover:shadow-xl hover:shadow-sunlight-400/10',
          'hover:-translate-y-1.5'
        )}
      >
        <div className="relative aspect-video overflow-hidden">
          <motion.img
            src={video.poster}
            alt={isZh ? video.titleZh : video.titleEn}
            className="w-full h-full object-cover"
            loading="lazy"
            whileHover={{ scale: 1.03 }}
            transition={{ duration: 300 }}
          />

          <motion.div
            className="absolute inset-0 bg-forest-900/40 flex items-center justify-center pointer-events-none"
            initial={{ opacity: 0 }}
            whileHover={{ opacity: 1 }}
            transition={{ duration: 250 }}
          >
            <div className="flex flex-col items-center gap-3">
              <div className="w-14 h-14 rounded-full bg-ivory-100/90 backdrop-blur-sm flex items-center justify-center">
                <Play className="w-6 h-6 text-forest-700 ml-1" fill="currentColor" />
              </div>
              <span className="text-white font-medium text-base tracking-wider">
                {isZh ? '观看作品' : 'View Film'}
              </span>
            </div>
          </motion.div>

          <div className="absolute top-3 right-3 px-2.5 py-1 rounded-md bg-ocean-900/70 backdrop-blur-sm">
            <span className="text-xs font-medium text-white">{video.duration}</span>
          </div>

          <div className="absolute bottom-3 left-3">
            <span className="px-2.5 py-1 rounded-md bg-forest-500/80 backdrop-blur-sm text-xs font-medium text-white">
              {isZh ? video.categoryZh : video.categoryEn}
            </span>
          </div>

          {video.awards && video.awards.length > 0 && (
            <div className="absolute bottom-3 right-3">
              <span className="px-2.5 py-1 rounded-md bg-amber-500/80 backdrop-blur-sm text-xs font-medium text-white">
                {isZh ? '获奖作品' : 'Award-winning'}
              </span>
            </div>
          )}
        </div>

        <div className="p-4 md:p-5">
          <h3 className="text-lg md:text-xl font-display font-semibold text-ocean-800 dark:text-ivory-50 mb-2 line-clamp-1">
            {isZh ? video.titleZh : video.titleEn}
          </h3>

          <p className="text-sm text-ocean-500 dark:text-ivory-400 mb-3 line-clamp-2">
            {isZh ? video.subtitleZh : video.subtitleEn}
          </p>

          <div className="flex items-center justify-between text-xs">
            <span className="text-ocean-400 dark:text-ivory-500">
              {isZh
                ? video.roles.slice(0, 2).map(r => r.zh).join(' · ')
                : video.roles.slice(0, 2).map(r => r.en).join(' · ')}
            </span>
            <span className="text-forest-500 dark:text-forest-400 font-medium">
              {video.year}
            </span>
          </div>
        </div>
      </div>
    </motion.div>
  );
}