import { useState, useRef, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import {
  X,
  ChevronLeft,
  ChevronRight,
  ExternalLink,
  Target,
  Users,
  Sparkles,
  Award,
  FileText,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import type { DeckWork } from '@/data/deckWorks';
import { assetPath } from '@/utils/assetPath';
import { usePdfRenderer } from '@/hooks/usePdfRenderer';

interface DeckDetailModalProps {
  deck: DeckWork;
  onClose: () => void;
}

export default function DeckDetailModal({ deck, onClose }: DeckDetailModalProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';
  const [currentPage, setCurrentPage] = useState(1);
  const [pageDirection, setPageDirection] = useState(0);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const title = isZh ? deck.titleZh : deck.titleEn;
  const category = isZh ? deck.categoryZh : deck.categoryEn;
  const overview = isZh ? deck.overviewZh : deck.overviewEn;
  const role = isZh ? deck.roleZh : deck.roleEn;
  const highlights = isZh ? deck.highlightsZh : deck.highlightsEn;
  const keywords = isZh ? deck.keywordsZh : deck.keywordsEn;
  const award = isZh ? deck.awardZh : deck.awardEn;

  const { loading, error, numPages, renderPage } = usePdfRenderer(deck.pdfUrl);

  // Render current page
  useEffect(() => {
    if (loading || error || !canvasRef.current || !containerRef.current) return;
    const width = containerRef.current.clientWidth;
    if (width > 0) {
      renderPage(currentPage, canvasRef.current, width).catch((err) => {
        console.error(`[DeckDetailModal] Failed to render page ${currentPage}:`, err);
      });
    }
  }, [loading, error, currentPage, renderPage, deck.pdfUrl]);

  // Keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft') goToPrevPage();
      if (e.key === 'ArrowRight') goToNextPage();
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [currentPage, numPages]);

  const goToPrevPage = useCallback(() => {
    if (currentPage > 1) {
      setPageDirection(-1);
      setCurrentPage((p) => p - 1);
    }
  }, [currentPage]);

  const goToNextPage = useCallback(() => {
    if (currentPage < numPages) {
      setPageDirection(1);
      setCurrentPage((p) => p + 1);
    }
  }, [currentPage, numPages]);

  const goToPage = useCallback((page: number) => {
    setPageDirection(page > currentPage ? 1 : -1);
    setCurrentPage(page);
  }, [currentPage]);

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-center justify-center p-3 md:p-6 bg-forest-900/70 backdrop-blur-sm"
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.92, opacity: 0, y: 30 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        exit={{ scale: 0.92, opacity: 0, y: 30 }}
        transition={{ duration: 0.4, ease: 'easeOut' }}
        className="relative w-full max-w-[1100px] max-h-[94vh] overflow-y-auto rounded-[24px] bg-ivory-50 dark:bg-ocean-800 shadow-2xl"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close button */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 z-30 p-2.5 rounded-full bg-white/90 dark:bg-ocean-700 text-forest-700 dark:text-ivory-300 hover:bg-white dark:hover:bg-ocean-600 transition-colors shadow-lg"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Header */}
        <div className="p-7 md:p-10 pb-5">
          <div className="flex items-center gap-4 mb-4">
            <div className="w-10 h-10 rounded-lg bg-forest-100 dark:bg-forest-900/30 flex items-center justify-center">
              <FileText className="w-5 h-5 text-forest-600 dark:text-forest-400" />
            </div>
            <div>
              <p className="text-[12px] font-medium text-forest-500 dark:text-forest-400 uppercase tracking-wider">
                {category} · {deck.year}
              </p>
              <h3 className="text-2xl md:text-3xl font-display font-bold text-ocean-800 dark:text-ivory-50 leading-tight">
                {title}
              </h3>
            </div>
          </div>
        </div>

        <div className="mx-7 md:mx-10 h-px bg-forest-100 dark:bg-ocean-700" />

        {/* Content */}
        <div className="p-7 md:p-10 pt-6 space-y-6">
          {/* Overview */}
          <section>
            <div className="flex items-center gap-2 mb-3">
              <Target className="w-4 h-4 text-forest-500 dark:text-forest-400" />
              <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                {isZh ? '项目简介' : 'Project Overview'}
              </h4>
            </div>
            <p className="text-[15px] text-ocean-600 dark:text-ivory-300 leading-[1.8]">{overview}</p>
          </section>

          {/* Role */}
          <section>
            <div className="flex items-center gap-2 mb-3">
              <Users className="w-4 h-4 text-forest-500 dark:text-forest-400" />
              <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                {isZh ? '我的职责' : 'My Role'}
              </h4>
            </div>
            <p className="text-[15px] text-ocean-600 dark:text-ivory-300">{role}</p>
          </section>

          {/* Highlights */}
          {highlights.length > 0 && (
            <section>
              <div className="flex items-center gap-2 mb-3">
                <Sparkles className="w-4 h-4 text-forest-500 dark:text-forest-400" />
                <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                  {isZh ? '关键亮点' : 'Key Highlights'}
                </h4>
              </div>
              <ul className="space-y-2.5">
                {highlights.map((h, idx) => (
                  <li key={idx} className="flex items-start gap-3 text-[14px] text-ocean-600 dark:text-ivory-300">
                    <span className="mt-2 w-1.5 h-1.5 rounded-full bg-forest-400 flex-shrink-0" />
                    <span className="leading-relaxed">{h}</span>
                  </li>
                ))}
              </ul>
            </section>
          )}

          {/* PDF Viewer */}
          {!error && !loading && (
            <section>
              <div className="flex items-center gap-2 mb-4">
                <FileText className="w-4 h-4 text-forest-500 dark:text-forest-400" />
                <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                  {isZh ? '方案浏览' : 'Deck Viewer'}
                </h4>
              </div>

              {/* PDF display area — 16:9 */}
              <div
                ref={containerRef}
                className="relative w-full overflow-hidden rounded-2xl border border-forest-200/60 dark:border-ocean-700"
                style={{ aspectRatio: '16 / 9', background: '#e9e7df' }}
              >
                <AnimatePresence mode="wait" custom={pageDirection}>
                  <motion.canvas
                    key={currentPage}
                    ref={canvasRef}
                    custom={pageDirection}
                    initial={{ opacity: 0, x: pageDirection * 30 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -pageDirection * 30 }}
                    transition={{ duration: 0.3 }}
                    className="absolute inset-0 w-full h-full"
                    style={{ objectFit: 'contain' }}
                  />
                </AnimatePresence>

                {/* Page indicator overlay */}
                <div className="absolute bottom-3 right-3 px-2.5 py-1 rounded-md bg-white/80 backdrop-blur-sm text-[11px] font-medium text-ocean-600">
                  {isZh ? `第${currentPage}页，共${numPages}页` : `Page ${currentPage} / ${numPages}`}
                </div>
              </div>

              {/* Navigation controls */}
              <div className="flex items-center justify-between mt-4">
                <button
                  onClick={goToPrevPage}
                  disabled={currentPage <= 1}
                  className={cn(
                    'inline-flex items-center gap-1 px-4 py-2 rounded-full text-[13px] font-medium',
                    'border-2 border-forest-300 text-forest-600 dark:text-forest-300',
                    'hover:bg-forest-50 dark:hover:bg-forest-900/20',
                    'transition-colors duration-200',
                    'disabled:opacity-30 disabled:cursor-not-allowed'
                  )}
                >
                  <ChevronLeft className="w-4 h-4" />
                  {isZh ? '上一页' : 'Previous'}
                </button>

                <span className="text-[13px] text-ocean-400 font-medium">
                  {isZh ? `第${currentPage}页 / 共${numPages}页` : `Page ${currentPage} / ${numPages}`}
                </span>

                <button
                  onClick={goToNextPage}
                  disabled={currentPage >= numPages}
                  className={cn(
                    'inline-flex items-center gap-1 px-4 py-2 rounded-full text-[13px] font-medium',
                    'border-2 border-forest-300 text-forest-600 dark:text-forest-300',
                    'hover:bg-forest-50 dark:hover:bg-forest-900/20',
                    'transition-colors duration-200',
                    'disabled:opacity-30 disabled:cursor-not-allowed'
                  )}
                >
                  {isZh ? '下一页' : 'Next'}
                  <ChevronRight className="w-4 h-4" />
                </button>
              </div>

              {/* Page thumbnails — desktop only */}
              {numPages > 1 && (
                <div className="hidden md:flex gap-2 mt-4 overflow-x-auto pb-2">
                  {Array.from({ length: numPages }, (_, i) => i + 1).map((page) => (
                    <button
                      key={page}
                      onClick={() => goToPage(page)}
                      className={cn(
                        'flex-shrink-0 px-3 py-1.5 rounded-md text-[11px] font-medium transition-all',
                        page === currentPage
                          ? 'bg-forest-600 text-white border-2 border-forest-600'
                          : 'bg-forest-50 text-forest-600 border-2 border-forest-200/60 hover:border-forest-300'
                      )}
                    >
                      {page}
                    </button>
                  ))}
                </div>
              )}

              {/* Open original PDF */}
              <div className="mt-4">
                <a
                  href={assetPath(deck.pdfUrl)}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={cn(
                    'inline-flex items-center gap-2 px-5 py-2.5 rounded-full',
                    'bg-forest-600 text-white',
                    'text-sm font-medium',
                    'hover:bg-forest-700',
                    'transition-colors duration-200'
                  )}
                >
                  {isZh ? '打开原始PDF' : 'Open PDF'}
                  <ExternalLink className="w-4 h-4" />
                </a>
              </div>
            </section>
          )}

          {/* Error state for PDF */}
          {error && (
            <section>
              <div className="p-6 rounded-xl bg-ivory-100 dark:bg-ocean-700/40 border border-forest-200/60 dark:border-ocean-600 text-center">
                <FileText className="w-8 h-8 text-forest-300/60 dark:text-forest-700/40 mx-auto mb-2" />
                <p className="text-sm text-ocean-400 dark:text-ivory-500">
                  {isZh ? '方案预览暂不可用' : 'Deck preview unavailable'}
                </p>
              </div>
            </section>
          )}

          {/* Keywords */}
          <section>
            <div className="flex items-center gap-2 mb-3">
              <Sparkles className="w-4 h-4 text-forest-500 dark:text-forest-400" />
              <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                {isZh ? '关键词' : 'Keywords'}
              </h4>
            </div>
            <div className="flex flex-wrap gap-2">
              {keywords.map((kw, idx) => (
                <span
                  key={idx}
                  className="px-3 py-1.5 rounded-full text-sm font-medium bg-forest-100/80 dark:bg-forest-900/40 text-forest-700 dark:text-forest-300 border border-forest-200/60 dark:border-forest-700/40"
                >
                  {kw}
                </span>
              ))}
            </div>
          </section>

          {/* Award */}
          {award && (
            <section>
              <div className="flex items-center gap-2 mb-3">
                <Award className="w-4 h-4 text-forest-500 dark:text-forest-400" />
                <h4 className="text-sm font-semibold text-forest-600 dark:text-forest-400 uppercase tracking-wider">
                  {isZh ? '奖项' : 'Award'}
                </h4>
              </div>
              <div className="flex items-center gap-3 p-4 rounded-xl bg-sunlight-50/80 dark:bg-sunlight-900/20 border border-sunlight-200/60 dark:border-sunlight-700/30">
                <Award className="w-5 h-5 text-sunlight-600 dark:text-sunlight-400 flex-shrink-0" />
                <span className="text-sm font-medium text-sunlight-700 dark:text-sunlight-400">
                  {award}
                </span>
              </div>
            </section>
          )}
        </div>
      </motion.div>
    </motion.div>
  );
}
