import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { cn } from '@/lib/utils';

interface ExperienceItem {
  id: string;
  period: string;
  organization: string;
  organizationZh?: string;
  role: string;
  roleZh?: string;
  summary: string;
  summaryZh?: string;
}

function ExperienceRow({ item, index, isLast }: { item: ExperienceItem; index: number; isLast: boolean }) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';

  const displayOrg = isZh && item.organizationZh ? item.organizationZh : item.organization;
  const displayRole = isZh && item.roleZh ? item.roleZh : item.role;
  const displaySummary = isZh && item.summaryZh ? item.summaryZh : item.summary;

  return (
    <motion.div
      initial={{ opacity: 0, x: -16 }}
      whileInView={{ opacity: 1, x: 0 }}
      viewport={{ once: true, margin: '-40px' }}
      transition={{ duration: 0.45, delay: index * 0.08, ease: 'easeOut' }}
      className="relative flex items-start"
    >
      {/* Left: Time column */}
      <div className="w-[110px] md:w-[140px] flex-shrink-0 pt-1">
        <p className="text-[15px] md:text-[17px] font-medium text-forest-500/80 font-sans leading-[1.6]">
          {item.period}
        </p>
      </div>

      {/* Middle: Timeline axis */}
      <div className="relative w-[28px] md:w-[32px] flex-shrink-0 flex justify-center self-stretch">
        {/* Vertical line */}
        <div
          className={cn(
            'absolute top-2 bottom-0 left-1/2 -translate-x-1/2 w-px',
            isLast ? 'h-2' : '',
            'bg-mint-300/50',
          )}
        />
        {/* Dot */}
        <div className="relative z-10 mt-2 w-2.5 h-2.5 rounded-full bg-mint-400 border-2 border-white shadow-sm" />
      </div>

      {/* Right: Content */}
      <div className="flex-1 min-w-0 pb-7 md:pb-8">
        <h4 className="text-[26px] md:text-[32px] font-display font-bold text-ocean-700 leading-tight">
          {displayOrg}
        </h4>
        <p className="text-[19px] md:text-[22px] font-semibold text-forest-600 font-sans mt-2">
          {displayRole}
        </p>
        <p className="text-[15px] md:text-[17px] text-forest-700/75 leading-[1.7] font-sans mt-2.5 max-w-[620px]">
          {displaySummary}
        </p>
      </div>
    </motion.div>
  );
}

export default function Timeline() {
  const { t, i18n } = useTranslation();
  const isZh = i18n.language === 'zh';

  const timelineItems = t('about.timelineItems', { returnObjects: true }) as ExperienceItem[];

  return (
    <div className="relative max-w-[1140px] mx-auto">
      {/* Section title */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.6 }}
        className="mb-8 md:mb-10"
      >
        <motion.span
          initial={{ opacity: 0, y: 10 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: 0.1 }}
          className="inline-block text-sm font-medium text-forest-500 tracking-[0.25em] uppercase mb-3 font-sans"
        >
          {t('about.timelineTitle')}
        </motion.span>
        <motion.h3
          initial={{ opacity: 0, y: 15 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: 0.2 }}
          className="text-3xl md:text-4xl font-display font-semibold text-forest-800"
        >
          {isZh ? '代表经历' : 'Representative Experience'}
        </motion.h3>
      </motion.div>

      {/* Timeline list */}
      <div className="relative">
        {timelineItems.map((item, index) => (
          <ExperienceRow
            key={item.id}
            item={item}
            index={index}
            isLast={index === timelineItems.length - 1}
          />
        ))}
      </div>
    </div>
  );
}
