import { NavLink } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { cn } from '@/lib/utils';

const navigationItems = [
  { path: '/', labelZh: '首页', labelEn: 'Home' },
  { path: '/about', labelZh: '关于', labelEn: 'About' },
  { path: '/artwork', labelZh: '作品', labelEn: 'Artwork' },
  { path: '/contact', labelZh: '联系', labelEn: 'Contact' },
];

export default function Navbar() {
  const { i18n } = useTranslation();
  const language = i18n.language === 'zh' ? 'zh' : 'en';

  return (
    <header className="global-header" role="banner">
      <div className="global-header-inner">
        <div className="global-language-area">
          <div
            className="global-language-switch"
            role="group"
            aria-label="Language switch"
          >
            <button
              type="button"
              onClick={() => i18n.changeLanguage('en')}
              className={cn('global-lang-btn', language === 'en' && 'global-lang-btn-active')}
              aria-pressed={language === 'en'}
            >
              EN
            </button>
            <button
              type="button"
              onClick={() => i18n.changeLanguage('zh')}
              className={cn('global-lang-btn', language === 'zh' && 'global-lang-btn-active')}
              aria-pressed={language === 'zh'}
            >
              中
            </button>
          </div>
        </div>

        <nav className="global-navigation" aria-label="Main navigation">
          {navigationItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              end={item.path === '/'}
              className={({ isActive }) =>
                cn('global-nav-link', isActive && 'global-nav-link-active')
              }
            >
              {language === 'zh' ? item.labelZh : item.labelEn}
            </NavLink>
          ))}
        </nav>
      </div>
    </header>
  );
}
