import { cn } from '@/lib/utils';

export interface NavSection {
  id: string;
  number: string;
  titleZh: string;
  titleEn: string;
  shortZh: string;
  shortEn: string;
}

interface SectionSideNavProps {
  sections: NavSection[];
  activeSection: string;
  onSectionClick: (id: string) => void;
  language: string;
  ariaLabel: string;
}

export function SectionSideNav({ sections, activeSection, onSectionClick, language, ariaLabel }: SectionSideNavProps) {
  const isZh = language === 'zh';

  return (
    <>
      {/* Desktop sidebar nav */}
      <nav
        aria-label={ariaLabel}
        className="hidden lg:block sticky top-[110px] self-start"
      >
        <ul className="space-y-1">
          {sections.map((section) => {
            const isActive = activeSection === section.id;
            const title = isZh ? section.titleZh : section.titleEn;

            return (
              <li key={section.id}>
                <button
                  onClick={() => onSectionClick(section.id)}
                  aria-current={isActive ? 'true' : undefined}
                  className={cn(
                    'group relative w-full text-left flex items-center gap-3',
                    'px-3 py-2.5 rounded-lg transition-all duration-300',
                    'focus:outline-none focus-visible:ring-2 focus-visible:ring-forest-400/50',
                    isActive
                      ? 'bg-forest-50/80'
                      : 'hover:bg-forest-50/40',
                  )}
                >
                  {/* Active indicator line */}
                  <span
                    className={cn(
                      'absolute left-0 top-1/2 -translate-y-1/2 w-[3px] rounded-full transition-all duration-300',
                      isActive ? 'h-5 bg-forest-500' : 'h-0 bg-transparent',
                    )}
                  />

                  <span
                    className={cn(
                      'text-[13px] font-mono font-medium tracking-wider transition-colors duration-300',
                      isActive ? 'text-forest-600' : 'text-forest-400/50 group-hover:text-forest-500/70',
                    )}
                  >
                    {section.number}
                  </span>

                  <span
                    className={cn(
                      'text-[14px] font-medium font-sans transition-all duration-300',
                      isActive
                        ? 'text-forest-700 font-semibold translate-x-[2px]'
                        : 'text-forest-500/70 group-hover:text-ocean-600 group-hover:translate-x-[2px]',
                    )}
                  >
                    {title}
                  </span>
                </button>
              </li>
            );
          })}
        </ul>
      </nav>

      {/* Mobile / tablet horizontal nav */}
      <nav
        aria-label={ariaLabel}
        className="lg:hidden sticky top-[64px] z-30 -mx-4 px-4 py-2.5 bg-ivory-50/90 dark:bg-ocean-900/90 backdrop-blur-sm border-b border-forest-100/50 dark:border-ocean-700/30"
      >
        <div
          className="flex gap-2 overflow-x-auto whitespace-nowrap"
          style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
          {sections.map((section) => {
            const isActive = activeSection === section.id;
            const shortTitle = isZh ? section.shortZh : section.shortEn;

            return (
              <button
                key={section.id}
                onClick={() => onSectionClick(section.id)}
                aria-current={isActive ? 'true' : undefined}
                className={cn(
                  'flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[13px] font-medium font-sans',
                  'flex-shrink-0 transition-all duration-300',
                  'focus:outline-none focus-visible:ring-2 focus-visible:ring-forest-400/50',
                  isActive
                    ? 'bg-forest-500 text-white shadow-sm'
                    : 'bg-forest-50/70 text-forest-600/80 border border-forest-200/40',
                )}
              >
                <span className={cn('text-[11px] font-mono', isActive ? 'text-white/70' : 'text-forest-400/60')}>
                  {section.number}
                </span>
                {shortTitle}
              </button>
            );
          })}
        </div>
      </nav>
    </>
  );
}
