import { useState, useEffect, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import PosterCard from '@/components/artwork/PosterCard';
import PosterLightbox from '@/components/artwork/PosterLightbox';
import VideoCard from '@/components/artwork/VideoCard';
import VideoDetailModal from '@/components/artwork/VideoDetailModal';
import VisualizationPreview from '@/components/artwork/VisualizationPreview';
import VisualizationDetailModal from '@/components/artwork/VisualizationDetailModal';
import AgentPlatformPreview from '@/components/artwork/AgentPlatformPreview';
import AgentPlatformDetailModal from '@/components/artwork/AgentPlatformDetailModal';
import EditorialCard from '@/components/artwork/EditorialCard';
import EditorialDetailModal from '@/components/artwork/EditorialDetailModal';
import DeckCard from '@/components/artwork/DeckCard';
import DeckDetailModal from '@/components/artwork/DeckDetailModal';
import { ArtworkSectionNav, artworkSections } from '@/components/artwork/ArtworkSectionNav';
import { posters, type Poster } from '@/data/posters';
import { videos, type Video } from '@/data/videos';
import { visualizations, type Visualization } from '@/data/visualizations';
import { agentPlatforms, type AgentPlatform } from '@/data/agentPlatforms';
import { editorialWorks, type EditorialWork } from '@/data/editorialWorks';
import { deckWorks, type DeckWork } from '@/data/deckWorks';

export default function Artwork() {
  const { t, i18n } = useTranslation();
  const isZhDark = i18n.language === 'zh';
  const [selectedPoster, setSelectedPoster] = useState<Poster | null>(null);
  const [isPosterLightboxOpen, setIsPosterLightboxOpen] = useState(false);
  const [selectedVideo, setSelectedVideo] = useState<Video | null>(null);
  const [isVideoModalOpen, setIsVideoModalOpen] = useState(false);
  const [selectedVisualization, setSelectedVisualization] = useState<Visualization | null>(null);
  const [isVizModalOpen, setIsVizModalOpen] = useState(false);
  const [selectedAgent, setSelectedAgent] = useState<AgentPlatform | null>(null);
  const [isAgentModalOpen, setIsAgentModalOpen] = useState(false);
  const [selectedEditorial, setSelectedEditorial] = useState<EditorialWork | null>(null);
  const [isEditorialModalOpen, setIsEditorialModalOpen] = useState(false);
  const [selectedDeck, setSelectedDeck] = useState<DeckWork | null>(null);
  const [isDeckModalOpen, setIsDeckModalOpen] = useState(false);

  const [activeSection, setActiveSection] = useState('poster-design');
  const sectionRefs = useRef<Record<string, HTMLElement | null>>({});
  const observerRef = useRef<IntersectionObserver | null>(null);

  const handlePosterClick = (poster: Poster) => {
    setSelectedPoster(poster);
    setIsPosterLightboxOpen(true);
  };

  const handleClosePosterLightbox = () => {
    setIsPosterLightboxOpen(false);
    setTimeout(() => setSelectedPoster(null), 300);
  };

  const handlePrevPoster = () => {
    if (!selectedPoster) return;
    const currentIndex = posters.findIndex((p) => p.id === selectedPoster.id);
    if (currentIndex > 0) {
      setSelectedPoster(posters[currentIndex - 1]);
    }
  };

  const handleNextPoster = () => {
    if (!selectedPoster) return;
    const currentIndex = posters.findIndex((p) => p.id === selectedPoster.id);
    if (currentIndex < posters.length - 1) {
      setSelectedPoster(posters[currentIndex + 1]);
    }
  };

  const handleVideoClick = (video: Video) => {
    setSelectedVideo(video);
    setIsVideoModalOpen(true);
  };

  const handleCloseVideoModal = () => {
    setIsVideoModalOpen(false);
    setTimeout(() => setSelectedVideo(null), 300);
  };

  const handlePrevVideo = () => {
    if (!selectedVideo) return;
    const currentIndex = videos.findIndex((v) => v.id === selectedVideo.id);
    if (currentIndex > 0) {
      setSelectedVideo(videos[currentIndex - 1]);
    }
  };

  const handleNextVideo = () => {
    if (!selectedVideo) return;
    const currentIndex = videos.findIndex((v) => v.id === selectedVideo.id);
    if (currentIndex < videos.length - 1) {
      setSelectedVideo(videos[currentIndex + 1]);
    }
  };

  const handleVisualizationClick = (viz: Visualization) => {
    setSelectedVisualization(viz);
    setIsVizModalOpen(true);
  };

  const handleCloseVizModal = () => {
    setIsVizModalOpen(false);
    setTimeout(() => setSelectedVisualization(null), 300);
  };

  const handleAgentClick = (agent: AgentPlatform) => {
    setSelectedAgent(agent);
    setIsAgentModalOpen(true);
  };

  const handleCloseAgentModal = () => {
    setIsAgentModalOpen(false);
    setTimeout(() => setSelectedAgent(null), 300);
  };

  const handleEditorialClick = (work: EditorialWork) => {
    setSelectedEditorial(work);
    setIsEditorialModalOpen(true);
  };

  const handleCloseEditorialModal = () => {
    setIsEditorialModalOpen(false);
    setTimeout(() => setSelectedEditorial(null), 300);
  };

  const handleSectionClick = useCallback((id: string) => {
    const el = sectionRefs.current[id];
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'start' });
      setActiveSection(id);
    }
  }, []);

  // IntersectionObserver for scroll spy
  useEffect(() => {
    if (observerRef.current) {
      observerRef.current.disconnect();
    }

    observerRef.current = new IntersectionObserver(
      (entries) => {
        // Find the entry with the highest intersection ratio that is intersecting
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio);

        if (visible.length > 0) {
          setActiveSection(visible[0].target.id);
        }
      },
      { rootMargin: '-20% 0px -65% 0px', threshold: [0, 0.1, 0.3, 0.5] }
    );

    artworkSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observerRef.current?.observe(el);
    });

    return () => observerRef.current?.disconnect();
  }, []);

  const setSectionRef = (id: string) => (el: HTMLElement | null) => {
    sectionRefs.current[id] = el;
  };

  // Shared section header component
  const SectionHeader = ({ sectionNum, title, subtitle }: { sectionNum: string; title: string; subtitle: string }) => (
    <div className="mb-10 md:mb-14">
      <span className="inline-block text-[18px] md:text-[20px] font-mono font-medium text-mint-500/70 tracking-[0.2em] mb-2">
        {sectionNum}
      </span>
      <h2 className="text-[36px] md:text-[44px] font-display font-semibold text-ocean-800 dark:text-ivory-50 mb-3 leading-tight">
        {title}
      </h2>
      <p className="text-base md:text-[18px] text-ocean-500 dark:text-ivory-400 max-w-2xl leading-relaxed">
        {subtitle}
      </p>
    </div>
  );

  return (
    <div className="min-h-screen bg-ivory-50 dark:bg-ocean-900 transition-colors duration-500">
      {/* Artwork page header */}
      <div className="pt-28 md:pt-32 px-4 md:px-8 lg:px-16">
        <div className="max-w-[1320px] mx-auto text-center mb-8 md:mb-12">
          <h1 className="text-4xl md:text-5xl font-display font-bold text-ocean-800 dark:text-ivory-50">
            {isZhDark ? '作品集' : 'Artwork'}
          </h1>
          <p className="mt-3 text-base md:text-lg text-ocean-500 dark:text-ivory-400">
            {isZhDark ? '涵盖海报、视频、长图文、数据可视化、智能体与策划案的完整作品展示。' : 'A collection of posters, videos, editorial works, visualizations, AI agents, and case studies.'}
          </p>
        </div>
      </div>

      {/* Main layout: sidebar + content */}
      <div className="px-4 md:px-8 lg:px-16 pb-16 md:pb-24">
        <div className="max-w-[1440px] mx-auto grid grid-cols-1 nav-lg-grid-sidebar gap-8 nav-lg-gap-12 items-start">
          {/* Left sidebar nav (desktop) / Top horizontal nav (mobile) */}
          <ArtworkSectionNav
            activeSection={activeSection}
            onSectionClick={handleSectionClick}
            language={i18n.language}
          />

          {/* Right content: all sections in order */}
          <div className="min-w-0 space-y-16 md:space-y-20">
            {/* 01 Poster Design */}
            <section
              id="poster-design"
              ref={setSectionRef('poster-design')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.posterSection')}
                title={t('artwork.posterTitle')}
                subtitle={t('artwork.posterSubtitle')}
              />
              <div className="grid grid-cols-1 poster-md-grid-cols-2 poster-lg-grid-cols-3 gap-6 poster-md-gap-8">
                {posters.map((poster, index) => (
                  <PosterCard
                    key={poster.id}
                    poster={poster}
                    index={index}
                    onClick={() => handlePosterClick(poster)}
                  />
                ))}
              </div>
            </section>

            {/* 02 Video Works */}
            <section
              id="video-works"
              ref={setSectionRef('video-works')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.videoSection')}
                title={t('artwork.videoTitle')}
                subtitle={t('artwork.videoSubtitle')}
              />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-7 md:gap-9">
                {videos.map((video, index) => (
                  <VideoCard
                    key={video.id}
                    video={video}
                    index={index}
                    onClick={() => handleVideoClick(video)}
                  />
                ))}
              </div>
            </section>

            {/* 03 Editorial Design */}
            <section
              id="editorial-design"
              ref={setSectionRef('editorial-design')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.editorialSection')}
                title={t('artwork.editorialTitle')}
                subtitle={t('artwork.editorialSubtitle')}
              />
              <div className="mt-2 grid grid-cols-1 md:grid-cols-2 gap-6">
                {editorialWorks.map((work, index) => (
                  <EditorialCard
                    key={work.id}
                    work={work}
                    index={index}
                    onViewDetails={() => handleEditorialClick(work)}
                    onReadArticle={() => window.open(work.articleUrl, '_blank', 'noopener noreferrer')}
                  />
                ))}
              </div>
            </section>

            {/* 04 Information Visualization */}
            <section
              id="information-visualization"
              ref={setSectionRef('information-visualization')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.vizSection')}
                title={t('artwork.vizTitle')}
                subtitle={t('artwork.vizSubtitle')}
              />
              {visualizations.map((viz) => (
                <VisualizationPreview
                  key={viz.id}
                  visualization={viz}
                  onViewDetails={() => handleVisualizationClick(viz)}
                />
              ))}
            </section>

            {/* 05 AI Agent Platform */}
            <section
              id="ai-agent-platform"
              ref={setSectionRef('ai-agent-platform')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.agentSection')}
                title={t('artwork.agentTitle')}
                subtitle={t('artwork.agentSubtitle')}
              />
              {agentPlatforms.map((agent) => (
                <AgentPlatformPreview
                  key={agent.id}
                  agent={agent}
                  onViewDetails={() => handleAgentClick(agent)}
                />
              ))}
            </section>

            {/* 06 Decks & Case Studies */}
            <section
              id="decks-case-studies"
              ref={setSectionRef('decks-case-studies')}
              className="scroll-mt-[130px]"
            >
              <SectionHeader
                sectionNum={t('artwork.deckSection')}
                title={t('artwork.deckTitle')}
                subtitle={t('artwork.deckSubtitle')}
              />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-7">
                {[...deckWorks].sort((a, b) => a.order - b.order).map((deck, index) => (
                  <DeckCard
                    key={deck.id}
                    deck={deck}
                    index={index}
                    onClick={() => {
                      setSelectedDeck(deck);
                      setIsDeckModalOpen(true);
                    }}
                  />
                ))}
              </div>
            </section>
          </div>
        </div>
      </div>

      <PosterLightbox
        poster={selectedPoster}
        posters={posters}
        isOpen={isPosterLightboxOpen}
        onClose={handleClosePosterLightbox}
        onPrev={handlePrevPoster}
        onNext={handleNextPoster}
      />

      <VideoDetailModal
        video={selectedVideo}
        videos={videos}
        isOpen={isVideoModalOpen}
        onClose={handleCloseVideoModal}
        onPrev={handlePrevVideo}
        onNext={handleNextVideo}
      />

      <VisualizationDetailModal
        visualization={selectedVisualization}
        isOpen={isVizModalOpen}
        onClose={handleCloseVizModal}
      />

      <AgentPlatformDetailModal
        agent={selectedAgent}
        isOpen={isAgentModalOpen}
        onClose={handleCloseAgentModal}
      />

      <EditorialDetailModal
        work={selectedEditorial}
        isOpen={isEditorialModalOpen}
        onClose={handleCloseEditorialModal}
      />

      {isDeckModalOpen && selectedDeck && (
        <DeckDetailModal
          deck={selectedDeck}
          onClose={() => {
            setIsDeckModalOpen(false);
            setTimeout(() => setSelectedDeck(null), 300);
          }}
        />
      )}
    </div>
  );
}
