import { useState, useEffect, useRef } from 'react';
import type { RefObject } from 'react';

interface ScrollPosition {
  scrollY: number;
  scrollX: number;
  scrollProgressY: number;
  scrollProgressX: number;
  direction: {
    y: 'up' | 'down' | null;
    x: 'left' | 'right' | null;
  };
}

interface UseScrollPositionOptions {
  element?: RefObject<HTMLElement> | null;
  throttleMs?: number;
  enabled?: boolean;
}

export function useScrollPosition({
  element = null,
  throttleMs = 16,
  enabled = true,
}: UseScrollPositionOptions = {}): ScrollPosition {
  const [scrollPosition, setScrollPosition] = useState<ScrollPosition>({
    scrollY: 0,
    scrollX: 0,
    scrollProgressY: 0,
    scrollProgressX: 0,
    direction: { y: null, x: null },
  });

  const lastYRef = useRef(0);
  const lastXRef = useRef(0);
  const throttleRef = useRef<number | null>(null);

  useEffect(() => {
    if (!enabled) return;

    const target = element?.current ?? window;

    const handleScroll = () => {
      if (throttleRef.current !== null) return;

      throttleRef.current = window.setTimeout(() => {
        throttleRef.current = null;

        let scrollY: number;
        let scrollX: number;
        let maxScrollY: number;
        let maxScrollX: number;

        if (element?.current) {
          const el = element.current;
          scrollY = el.scrollTop;
          scrollX = el.scrollLeft;
          maxScrollY = el.scrollHeight - el.clientHeight;
          maxScrollX = el.scrollWidth - el.clientWidth;
        } else {
          scrollY = window.scrollY || window.pageYOffset;
          scrollX = window.scrollX || window.pageXOffset;
          maxScrollY = document.documentElement.scrollHeight - window.innerHeight;
          maxScrollX = document.documentElement.scrollWidth - window.innerWidth;
        }

        const scrollProgressY = maxScrollY > 0 ? Math.min(1, Math.max(0, scrollY / maxScrollY)) : 0;
        const scrollProgressX = maxScrollX > 0 ? Math.min(1, Math.max(0, scrollX / maxScrollX)) : 0;

        const directionY: 'up' | 'down' | null =
          scrollY > lastYRef.current ? 'down' : scrollY < lastYRef.current ? 'up' : null;
        const directionX: 'left' | 'right' | null =
          scrollX > lastXRef.current ? 'right' : scrollX < lastXRef.current ? 'left' : null;

        lastYRef.current = scrollY;
        lastXRef.current = scrollX;

        setScrollPosition({
          scrollY,
          scrollX,
          scrollProgressY,
          scrollProgressX,
          direction: { y: directionY, x: directionX },
        });
      }, throttleMs);
    };

    target.addEventListener('scroll', handleScroll, { passive: true });
    handleScroll();

    return () => {
      target.removeEventListener('scroll', handleScroll);
      if (throttleRef.current !== null) {
        clearTimeout(throttleRef.current);
        throttleRef.current = null;
      }
    };
  }, [element, throttleMs, enabled]);

  return scrollPosition;
}
