import { useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { ExternalLink, Eye, Maximize2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { EditorialWork } from '@/data/editorialWorks';

interface EditorialCardProps {
  work: EditorialWork;
  index: number;
  onViewDetails: () => void;
  onReadArticle: () => void;
}

export default function EditorialCard({ work, index, onViewDetails, onReadArticle }: EditorialCardProps) {
  const { i18n } = useTranslation();
  const isZh = i18n.language === 'zh';
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);

  const title = isZh ? work.titleZh : work.titleEn;
  const category = isZh ? work.categoryZh : work.categoryEn;
  const overview = isZh ? work.overviewZh : work.overviewEn;
  const roles = isZh ? work.roleZh : work.roleEn;

  const handleImageLoad = useCallback(() => {
    setImageLoaded(true);
  }, []);

  const handleImageError = useCallback(() => {
    console.error(`[EditorialCard] Image failed to load: ${work.fullImage}`);
    setImageError(true);
  }, [work.fullImage]);

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 0.6, delay: index * 0.08, ease: 'easeOut' }}
      className={cn(
        'group flex flex-col',
        'overflow-hidden',
        'bg-ivory-50 dark:bg-ocean-800',
        'border border-forest-200/60 dark:border-ocean-700',
        'rounded-[20px]',
        'shadow-lg shadow-forest-900/5 dark:shadow-black/10',
        'transition-all duration-300 ease-out',
        'hover:-translate-y-[3px]',
        'hover:border-forest-300 dark:hover:border-forest-600',
        'hover:shadow-xl hover:shadow-forest-900/10 dark:hover:shadow-black/20'
      )}
    >
      {/* Compact preview window — no internal scroll */}
      <div
        className="relative flex-shrink-0 w-full overflow-hidden cursor-pointer h-[200px] sm:h-[220px] md:h-[240px] bg-[#f4f1e8] dark:bg-ocean-700/30"
        onClick={onViewDetails}
        style={{ borderRadius: '20px 20px 0 0' }}
      >
        {/* Skeleton */}
        {!imageLoaded && !imageError && (
          <div className="w-full h-full animate-pulse bg-gradient-to-b from-ivory-100 via-ivory-200 to-ivory-100 dark:from-ocean-700/40 dark:via-ocean-700/60 dark:to-ocean-700/40" />
        )}

        {imageError ? (
          <div className="w-full h-full flex flex-col items-center justify-center bg-gradient-to-br from-ivory-50 via-ivory-100 to-ivory-200 dark:from-ocean-700/40 dark:via-ocean-800 dark:to-ocean-900">
            <Eye className="w-10 h-10 text-forest-200/60 dark:text-forest-700/40 mb-3" />
            <p className="text-sm text-ocean-300 dark:text-ivory-500">
              {isZh ? '图片加载失败' : 'Image unavailable'}
            </p>
          </div>
        ) : (
          <img
            src={work.fullImage}
            alt={title}
            loading="lazy"
            decoding="async"
            onLoad={handleImageLoad}
            onError={handleImageError}
            className={cn(
              'block w-full h-full',
              'object-cover object-top',
              'transition-all duration-500',
              imageLoaded ? 'opacity-100' : 'opacity-0',
              'group-hover:scale-[1.025]'
            )}
          />
        )}

        {/* Gradient overlay at bottom — hints at more content */}
        {imageLoaded && !imageError && (
          <div
            className="absolute bottom-0 left-0 right-0 pointer-events-none transition-all duration-300"
            style={{
              height: '38%',
              background: 'linear-gradient(to bottom, transparent, rgba(18, 55, 48, 0.72))',
            }}
          />
        )}

        {/* "View Full Design" overlay */}
        {imageLoaded && !imageError && (
          <div className="absolute bottom-0 left-0 right-0 flex items-center justify-center pb-4 pointer-events-none">
            <span
              className={cn(
                'inline-flex items-center gap-1.5 text-[13px] font-medium text-white',
                'transition-all duration-300',
                'opacity-80 group-hover:opacity-100',
                'translate-y-1 group-hover:translate-y-0'
              )}
            >
              <Maximize2 className="w-3.5 h-3.5" />
              {isZh ? '查看完整设计' : 'View Full Design'}
            </span>
          </div>
        )}
      </div>

      {/* Text info area */}
      <div className="flex flex-col flex-1 p-5 space-y-3">
        {/* Category */}
        <div className="flex items-center gap-2 text-xs font-medium tracking-wide">
          <span className="uppercase text-forest-600 dark:text-forest-400">{category}</span>
          <span className="w-1 h-1 rounded-full bg-forest-300 dark:bg-forest-600" />
          <span className="text-ocean-400 dark:text-ivory-500">{work.year}</span>
        </div>

        {/* Title */}
        <h3 className="text-lg font-display font-semibold leading-snug text-ocean-800 dark:text-ivory-50">
          {title}
        </h3>

        {/* Brief overview — max 3 lines */}
        <p className="text-sm leading-relaxed text-ocean-500 dark:text-ivory-400 line-clamp-3">
          {overview}
        </p>

        {/* Role tags — max 2 lines */}
        <div className="flex flex-wrap items-center gap-1.5">
          {roles.map((role, i) => (
            <span
              key={`${role}-${i}`}
              className={cn(
                'inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium',
                'bg-forest-50 text-forest-700 border border-forest-200/80',
                'dark:bg-forest-900/30 dark:text-forest-300 dark:border-forest-700/60'
              )}
            >
              {role}
            </span>
          ))}
        </div>

        {/* Action buttons — fixed at bottom */}
        <div className="flex items-center gap-3 mt-auto pt-3">
          <button
            onClick={onViewDetails}
            className={cn(
              'inline-flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium',
              'bg-forest-600 text-white',
              'hover:bg-forest-700',
              'transition-colors duration-200',
            )}
          >
            <Eye className="w-3.5 h-3.5" />
            {isZh ? '查看完整设计' : 'View Full Design'}
          </button>

          <button
            onClick={onReadArticle}
            className={cn(
              'inline-flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium',
              'border-2 border-forest-400 text-forest-600 dark:text-forest-300',
              'hover:bg-forest-50 dark:hover:bg-forest-900/20',
              'transition-colors duration-200',
            )}
          >
            <ExternalLink className="w-3.5 h-3.5" />
            {isZh ? '阅读公众号原文' : 'Read Original'}
          </button>
        </div>
      </div>
    </motion.div>
  );
}
