import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { cn } from '@/lib/utils';

interface SectionWrapperProps {
  id?: string;
  children: React.ReactNode;
  className?: string;
  sectionNumber?: string;
  title?: string;
  titleKey?: string;
  subtitle?: string;
  subtitleKey?: string;
}

export default function SectionWrapper({
  id,
  children,
  className,
  sectionNumber,
  title,
  titleKey,
  subtitle,
  subtitleKey,
}: SectionWrapperProps) {
  const { t } = useTranslation();

  const displayTitle = titleKey ? t(titleKey) : title;
  const displaySubtitle = subtitleKey ? t(subtitleKey) : subtitle;

  return (
    <section id={id} className={cn('relative py-20 md:py-28', className)}>
      <div className="container mx-auto px-4 md:px-6 max-w-6xl">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: '-100px' }}
          transition={{ duration: 0.8, ease: 'easeOut' }}
        >
          {(sectionNumber || displayTitle) && (
            <div className="mb-12 md:mb-16 text-center">
              {sectionNumber && (
                <motion.span
                  initial={{ opacity: 0, y: 10 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.6, delay: 0.1 }}
                  className="block text-sm font-medium text-ocean-400 dark:text-ocean-300 tracking-[0.3em] uppercase mb-4 font-sans"
                >
                  {sectionNumber}
                </motion.span>
              )}
              {displayTitle && (
                <motion.h2
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.7, delay: 0.2 }}
                  className="text-3xl md:text-4xl lg:text-5xl font-display font-semibold text-ocean-800 dark:text-ivory-50 tracking-tight"
                >
                  {displayTitle}
                </motion.h2>
              )}
              {displaySubtitle && (
                <motion.p
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.7, delay: 0.3 }}
                  className="mt-4 text-base md:text-lg text-ocean-600 dark:text-ivory-300 max-w-2xl mx-auto font-sans"
                >
                  {displaySubtitle}
                </motion.p>
              )}
            </div>
          )}
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: '-50px' }}
            transition={{ duration: 0.8, delay: 0.2, ease: 'easeOut' }}
          >
            {children}
          </motion.div>
        </motion.div>
      </div>
    </section>
  );
}
